class ThemeManager{constructor(){this.STORAGE_KEY='f1-news-theme',this.THEME_LIGHT='light',this.THEME_DARK='dark',this.THEME_AUTO='auto',this.init()}init(){this.setupListener(),this.applyStoredTheme(),this.setupThemeToggleButton()}getSystemTheme(){return window.matchMedia&&window.matchMedia('(prefers-color-scheme: dark)').matches?this.THEME_DARK:this.THEME_LIGHT}getStoredTheme(){try{return localStorage.getItem(this.STORAGE_KEY)||this.THEME_AUTO}catch(a){return console.warn('localStorage not available:',a),this.THEME_AUTO}}saveTheme(a){try{localStorage.setItem(this.STORAGE_KEY,a)}catch(a){console.warn('Failed to save theme:',a)}}getEffectiveTheme(){const a=this.getStoredTheme();return a===this.THEME_AUTO?this.getSystemTheme():a}applyStoredTheme(){const a=this.getEffectiveTheme();this.applyTheme(a)}applyTheme(b){const a=document.documentElement;b===this.THEME_DARK?(a.classList.add('dark'),a.classList.remove('light'),document.body.classList.add('dark'),document.body.classList.remove('light')):(a.classList.remove('dark'),a.classList.add('light'),document.body.classList.remove('dark'),document.body.classList.add('light')),this.updateToggleButtonState(b),window.dispatchEvent(new CustomEvent('themechange',{detail:{theme:b}}))}toggleTheme(){const b=this.getStoredTheme();let a;b===this.THEME_AUTO?a=this.getSystemTheme()===this.THEME_DARK?this.THEME_LIGHT:this.THEME_DARK:b===this.THEME_LIGHT?a=this.THEME_DARK:a=this.THEME_LIGHT,this.setTheme(a)}setTheme(a){this.saveTheme(a),this.applyTheme(a)}updateToggleButtonState(a){const b=document.querySelectorAll('#theme-toggle, .theme-toggle');b.forEach(b=>{a===this.THEME_DARK?(b.setAttribute('aria-label','Switch to light mode'),b.setAttribute('title','Switch to light mode (切换到浅色模式)')):(b.setAttribute('aria-label','Switch to dark mode'),b.setAttribute('title','Switch to dark mode (切换到深色模式)'))})}setupThemeToggleButton(){const a=document.querySelectorAll('#theme-toggle, .theme-toggle');a.forEach(a=>{a.addEventListener('click',()=>{this.toggleTheme()})})}setupListener(){if(!window.matchMedia)return;const a=window.matchMedia('(prefers-color-scheme: dark)');a.addEventListener?a.addEventListener('change',a=>{const b=this.getStoredTheme();b===this.THEME_AUTO&&this.applyTheme(a.matches?this.THEME_DARK:this.THEME_LIGHT)}):a.addListener&&a.addListener(a=>{const b=this.getStoredTheme();b===this.THEME_AUTO&&this.applyTheme(a.matches?this.THEME_DARK:this.THEME_LIGHT)})}getCurrentTheme(){const a=document.documentElement;return a.classList.contains('dark')?this.THEME_DARK:this.THEME_LIGHT}}document.readyState==='loading'?document.addEventListener('DOMContentLoaded',()=>{window.themeManager=new ThemeManager}):window.themeManager=new ThemeManager,typeof module!='undefined'&&module.exports&&(module.exports=ThemeManager)